const results = [];
const now = Date.now();

try {
  const r = $('Check: WF-301 SEO Content').first().json;
  const last = (r.data||[])[0];
  if (!last) {
    results.push({ name:'WF-301 SEO Content', ok:false, status:'нет запусков', age:999 });
  } else {
    const ageH = Math.round((now - new Date(last.stoppedAt||last.startedAt).getTime())/3600000);
    const isErr = last.status === 'error';
    const isTooOld = ageH > 26;
    // For weekly WF-205: only alert if error is fresh (< 7 days) AND not expected wait
    const gracePeriod = 0;
    const realError = isErr && ageH < (gracePeriod > 0 ? gracePeriod : 26);
    const missedSchedule = !isErr && isTooOld && true;
    results.push({ 
      name:'WF-301 SEO Content', 
      ok: !realError && !missedSchedule, 
      status: last.status,
      age: ageH,
      detail: realError ? '❌ ошибка' : missedSchedule ? '⏰ пропустил расписание' : '✅'
    });
  }
} catch(e) { results.push({ name:'WF-301 SEO Content', ok:false, status:'ошибка API', age:0 }); }

