// Yandex quota
let yaLine = '';
try {
  const ya = $('Яндекс: квота').first().json;
  const daily = ya.daily_quota || 890;
  const rem = ya.quota_remainder ?? 0;
  const used = daily - rem;
  const pct = Math.round(used/daily*100);
  const bar = '█'.repeat(Math.round(pct/10)) + '░'.repeat(10-Math.round(pct/10));
  yaLine = `\n━━━━━━━━━━━━━━━━━━━━\n🕷 Crawl квоты сегодня:\n  Яндекс:  ${bar} ${used}/${daily} (${pct}%)`;
} catch(e) {}

const errors = results.filter(r => !r.ok);
const ok = results.filter(r => r.ok);
const msk = new Date(now + 3*3600000);
const t = msk.toLocaleTimeString('ru-RU',{timeZone:'UTC',hour:'2-digit',minute:'2-digit'});

// Only send alert if errors > 0 OR send daily OK summary at 12:00 MSK
const isMorning = msk.getHours() === 12 && msk.getMinutes() < 60;
const hasErrors = errors.length > 0;

let msg = '';
let sendIt = false;

if (hasErrors) {
  msg = `🚨 АЛЕРТ: ${errors.length} проблем (${t} MSK)\n\n`;
  msg += errors.map(r => `${r.detail} ${r.name} (${r.age}ч назад)`).join('\n');
  msg += `\n\n✅ Работают:\n` + ok.map(r=>`  ${r.name} (${r.age}ч)`).join('\n');
  msg += yaLine;
  sendIt = true;
} else if (isMorning) {
  // Daily OK summary at noon MSK only
  msg = `✅ Всё работает (${t} MSK)\n\n` + ok.map(r=>`  ✅ ${r.name} (${r.age}ч)`).join('\n') + yaLine;
  sendIt = true;
}

return [{ json: { text: msg, send: sendIt } }];
